#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int x, team1 = 0, team2 = 0;
        for (int i = 1; i <= 10; ++i) {
            scanf("%d", &x);
            if (i % 2) team1 += x; else team2 += x;
        }
        if (team1 > team2) printf("1\n");
        else if (team2 > team1) printf("2\n");
        else printf("0\n");
    }
    return 0;
}

