import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        team1 = team2 = 0
        for i in range(1, 11):
            v = int(next(it))
            if i % 2:
                team1 += v
            else:
                team2 += v
        if team1 > team2:
            out.append('1')
        elif team2 > team1:
            out.append('2')
        else:
            out.append('0')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

